const data = $input.first().json;
const reports = data.reports || [];

// Rule-based evaluation
const contamination = reports.filter(r => r.custom_fields?.contaminationSuspected === true);
const noWater = reports.filter(r => r.custom_fields?.waterUnavailable === true);
const longDisruption = reports.filter(r => (r.custom_fields?.durationHours || 0) >= 6);
const criticalSeverity = reports.filter(r => r.severity === 'Critical');

let severity = 'Low';
let probability = 0.05;
let shouldAlert = false;
let message = '';

if (contamination.length >= 1) {
  severity = 'Critical';
  probability = 0.95;
  shouldAlert = true;
  message = `CONTAMINATION ALERT: ${contamination.length} reports of suspected water contamination. Do not drink tap water.`;
} else if (criticalSeverity.length >= 2 || reports.length >= 12) {
  severity = 'Critical';
  probability = 0.85;
  shouldAlert = true;
  message = `${reports.length} water supply disruption reports. Mass outage detected.`;
} else if (noWater.length >= 5 || reports.length >= 6) {
  severity = 'High';
  probability = 0.70;
  shouldAlert = true;
  message = `${noWater.length} areas without running water. ${reports.length} total reports.`;
} else if (longDisruption.length >= 2 || reports.length >= 3) {
  severity = 'Medium';
  probability = 0.45;
  shouldAlert = true;
  message = `${reports.length} water disruption reports. Some extended outages reported.`;
}

return [{ json: {
  incidentType: 'water_supply_disruption',
  severity,
  probability,
  reportCount: reports.length,
  contaminationReports: contamination.length,
  noWaterReports: noWater.length,
  longDisruptionReports: longDisruption.length,
  message,
  shouldAlert,
  timestamp: new Date().toISOString()
}}];
